    echo "${sequence}" | grep -b -o 'GACTGA\|AACTGA\|GAATGA\|AAATGA' | awk -F: -v name="${name}" '{OFS="\t"; print 20-$1-6, name, $2}' >> motifs_INR_newTSS_minus.txt
done < newTSS_INR_regions_minus.bed


